package com.finbit.fiuadapter.webservice.utils;

import com.finbit.fiuadapter.webservice.config.ApplicationConfiguration;
import com.finbit.fiuadapter.webservice.constants.GeneralConstants;
import com.finbit.fiuadapter.webservice.exceptions.InvalidRequestException;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.http.HttpStatus;
import org.springframework.stereotype.Service;

import java.text.ParseException;
import java.text.SimpleDateFormat;
import java.util.Date;
import java.util.TimeZone;

@Service
public class TimeStampValidation {
    @Autowired
    ApplicationConfiguration applicationConfigurationBean;

    public boolean validateTimeStamp(String timestamp, String txnId) throws InvalidRequestException {
        //creates a formatter that parses the date in the given format
        try {
            SimpleDateFormat sdf = new SimpleDateFormat("yyyyy-MM-dd'T'HH:mm:ss.SSS'Z'");
            sdf.setTimeZone(TimeZone.getTimeZone("UTC"));
            Date date = sdf.parse(timestamp);
            long timeInMillis = date.getTime();
            long fifteenAgo = System.currentTimeMillis() - (applicationConfigurationBean.getApplicationConfigurationBean().getTimestampValidity()*60*1000);
            if(new Date().before(date)){
                throw new InvalidRequestException(txnId, GeneralConstants.INVALID_REQUEST,GeneralConstants.TIMESTAMP_FUTURE, HttpStatus.BAD_REQUEST);
            }
            if (timeInMillis < fifteenAgo) {
                return false;
            }
            else{
                return true;
            }
        } catch (ParseException e){
            throw new InvalidRequestException(txnId,GeneralConstants.INVALID_REQUEST,GeneralConstants.DATE_PARSING_ERROR, HttpStatus.BAD_REQUEST);
        }
    }
}

